CREATE OR REPLACE FUNCTION fpb_agent_count_mem ( as_agent_no CHAR ,ai_year integer ,ai_month integer ) RETURNS bigint AS $body$
DECLARE

li_keep_mem integer;

BEGIN
--ตัวแทนที่หักให้ได้ครบ มากกว่าหรือเท่ากับยอดที่เรียกเก็บ  
        select count( 1 ) into STRICT li_keep_mem
        from (
        SELECT   sc_kep_t_monthly_salaryin.membership_no
        , sc_kep_t_monthly_receive.kep_limit AS keeping_amount
        , sc_kep_t_monthly_salaryin.keeping_real
        from sc_kep_t_monthly_salaryin
        ,sc_kep_t_monthly_receive
        where 1=1       
        and sc_kep_t_monthly_salaryin.receive_year = sc_kep_t_monthly_receive.receive_year
        and sc_kep_t_monthly_salaryin.receive_month = sc_kep_t_monthly_receive.receive_month
        and sc_kep_t_monthly_salaryin.salary_time = sc_kep_t_monthly_receive.seq_no
        and sc_kep_t_monthly_salaryin.membership_no  = sc_kep_t_monthly_receive.membership_no
        and sc_kep_t_monthly_salaryin.keeping_real > 0
        and sc_kep_t_monthly_salaryin.receive_year = ai_year
        and sc_kep_t_monthly_salaryin.receive_month = ai_month 
        and sc_kep_t_monthly_receive.agent_no = as_agent_no
        ) tb 
        where keeping_amount <= keeping_real
;
return li_keep_mem;

END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
